import axios from 'axios';

// Detect the backend base URL dynamically:
// - If VITE_API_BASE_URL is set in .env, use it.
// - If running on a non-localhost machine (LAN IP), auto-resolve to that machine's backend.
// - Otherwise fall back to relative URLs (same-origin, e.g. when serving frontend from backend).
let resolvedBaseUrl = import.meta.env.VITE_API_BASE_URL;
if (!resolvedBaseUrl) {
  const hostname = window.location.hostname;
  if (hostname && hostname !== 'localhost' && hostname !== '127.0.0.1') {
    // Same machine that's serving the frontend likely also runs the backend on port 5000
    resolvedBaseUrl = `http://${hostname}:5000`;
  }
}
const BASE_URL = resolvedBaseUrl || '';

const api = axios.create({
  baseURL: BASE_URL ? `${BASE_URL}/api` : '/api',
  timeout: 300000,
});

api.interceptors.request.use(
  config => {
    console.log('API request:', config.baseURL + config.url);
    return config;
  },
  error => Promise.reject(error)
);

/**
 * resolveUrl — Converts any stored URL/path to an absolute URL.
 *
 * Audio/image files stored as relative paths like "/uploads/audios/file.mp3"
 * need to be prefixed with the backend host when accessed from another machine.
 *
 * Examples:
 *   "/uploads/audios/foo.mp3"  → "http://192.168.x.x:5000/uploads/audios/foo.mp3"
 *   "http://example.com/x.mp3" → "http://example.com/x.mp3"  (unchanged)
 *   ""                         → ""
 */
function resolveUrl(url) {
  if (!url) return '';

  // Already absolute URLs — return as-is
  if (url.startsWith('http') || url.startsWith('blob:') || url.startsWith('data:')) {
    return url;
  }

  // Relative path — prefix with BASE_URL (backend host) if available
  const base = BASE_URL || '';
  const path = url.startsWith('/') ? url : `/${url}`;
  return base ? `${base}${path}` : path;
}

export { BASE_URL, resolveUrl };
export default api;
